import React, { Component } from 'react'
import List from './List.js'
import Pagination from './Pagination.js'

class Filters extends Component {
  state={
    selected_pays:0,
    selected_wilaya:0,
    selected_commune:0,
    commercial:'',
  }

  get_by_page=(page)=>{
    this.props.getCommerciaux(this.state.selected_pays,this.state.selected_wilaya,this.state.selected_commune,this.state.commercial,page)
  }

  render() {
    return (
      <React.Fragment>
      <div className="py-4 container text-secondary">
        <div className="row">
        <div className="col-md pb-2">
          <b>Pays:</b>
          <select className="form-control"
          onChange={(e)=>{this.setState({selected_pays:e.target.value,selected_wilaya:0,selected_commune:0});
          this.props.getCommerciaux(e.target.value,"","",this.state.commercial)}}>
          <option value="0">Tous les pays</option>
          {this.props.pays.map(pys=>(
            <option key={pys.id} value={pys.id} >{pys.nom}</option>
          ))}
          </select>
        </div>
          <div className="col-md pb-2">
            <b>wilaya:</b>
            <select className="form-control"
            onChange={(e)=>{this.setState({selected_wilaya:e.target.value,selected_commune:0});
            this.props.getCommerciaux("",e.target.value,"",this.state.commercial)}}>
            <option value="0">Toutes les wilayas</option>
            {this.props.pays.map(pys=>{
              if((this.state.selected_pays==0) ||(this.state.selected_pays==pys.id))
              return pys.wilayas_list.map(wilaya=>(
                <option key={wilaya.id} value={wilaya.id}>{wilaya.nom}</option>
              ))
            })}
            </select>
          </div>
          <div className="col-md pb-2">
            <b>commune:</b>
            <select className="form-control"
            onChange={(e)=>{this.setState({selected_commune:e.target.value});
            this.props.getCommerciaux("","",e.target.value,this.state.commercial)}}>
            <option value="0">Toutes les communes</option>
            {this.props.pays.map(pys=>{
              if((this.state.selected_pays==0) ||(this.state.selected_pays==pys.id))
              return pys.wilayas_list.map(wilaya=>{
                if((this.state.selected_wilaya==0) ||(this.state.selected_wilaya==wilaya.id))
                return wilaya.communes.map(commune=>(
                  <option key={commune.id} value={commune.id}>{commune.nom}</option>
                ))
              })
            })}
            </select>
          </div>


          <div className="col-md pb-2">
            <b>nom:</b>
            <input type="text" className="form-control"
            onChange={(e)=>{this.setState({commercial:e.target.value});
            this.props.getCommerciaux(this.state.selected_pays,this.state.selected_wilaya,this.state.selected_commune,e.target.value)
            }}/>
          </div>


        </div>
      </div>
      <List commerciaux={this.props.commerciaux} length={this.props.length}/>
      <Pagination
        pages={this.props.pages}
        page={this.props.page}
        next={this.props.next}
        previous={this.props.previous}
        getByPage={this.get_by_page}
      />
      </React.Fragment>
    )
  }
}

export default Filters
