import React, { Component } from 'react'
import {Link} from "react-router-dom";
import { faUser,faUserCog,faUsers,faPlusCircle,faSignOutAlt,faUserMd,faSearch,faCalendarCheck} from "@fortawesome/free-solid-svg-icons";
import { FontAwesomeIcon } from "@fortawesome/react-fontawesome";
import logo from '../img/logo.png'

class Header extends Component {
  render() {
    return (
      <React.Fragment>
      <div className="bg-green py-1">
        <div className=" container text-md-right text-center text-white">
          {new Date().toLocaleDateString()} &nbsp;  &nbsp;  &nbsp;
          <a className="text-white" href="/rapports/"><FontAwesomeIcon icon={faUser} /> {this.props.user.nom}</a> &nbsp;  &nbsp; &nbsp;  
          <div className="d-md-none d-block"></div>
          <a  className="text-white" href="/accounts/logout/"><FontAwesomeIcon icon={faSignOutAlt} /> Deconnexion</a>
        </div>
      </div>

      <nav className="navbar navbar-expand-lg navbar-light bg-light shadow">
        <a className="navbar-brand" href=""><img src={logo} style={{maxHeight:"50px"}}/></a>
        <button className="navbar-toggler" type="button" data-toggle="collapse" data-target="#navbarNavAltMarkup" aria-controls="navbarNavAltMarkup" aria-expanded="false" aria-label="Toggle navigation">
          <span className="navbar-toggler-icon"></span>
        </button>
        <div className="collapse navbar-collapse" id="navbarNavAltMarkup">
            <h1 className='font-weight-light text-green d-none d-md-block'> {this.props.title} </h1>
          <div className="navbar-nav ml-auto ">
            <a className="nav-item nav-link my-1 mx-md-2 btn"  href="/admin/"><FontAwesomeIcon icon={faUserCog} /> Administration</a>
            <Link className="nav-item nav-link my-1 mx-md-2 btn" to="/"><FontAwesomeIcon icon={faCalendarCheck} /> Rapports</Link>
            <Link className="nav-item nav-link my-1 mx-md-2 btn" to="/medecins"><FontAwesomeIcon icon={faUserMd} /> Medecins</Link>
            <a className="nav-item nav-link my-1 mx-md-2 btn" href="/orders/front/"><FontAwesomeIcon icon={faCalendarCheck} /> Commandes</a>
            <a className="nav-item nav-link my-1 mx-md-2 btn" href="/orders/front/exits/"><FontAwesomeIcon icon={faCalendarCheck} /> Sorties</a>
          </div>
        </div>
      </nav>
      <h5 className="text-green text-center pt-3 d-md-none">{this.props.title}</h5>
</React.Fragment>

    )
  }
}

export default Header
