import React, {useEffect, useState} from 'react'
import Filters from './Filters'
import List from './List'



const Orders=(props)=> {


    const [commerciaux, setcommerciaux] = useState([]);
    const [produits, setproduits] = useState([])

    const [orders, setorders] = useState([])

    useEffect(() => {
        props.changeTitle("commandes");
        get_commerciaux()
        get_produits()
    }, [])
    


   const  get_commerciaux=async(pays="",wilaya="",commune="",commercial="",page="")=>{
        await fetch(props.urls.commerciaux)
        .then(response=>response.json())
        .then(response=>setcommerciaux(response))
      }


    const get_produits=async()=>{
        await fetch(props.urls.produits)
        .then(response=>response.json())
        .then(response=>setproduits(response))
    }  



  return (
    <>
        <Filters
            pays={props.pays}
            commerciaux={commerciaux}
            produits={produits}
            urls={props.urls}
            setorders={setorders}
        />
        <List setorders={setorders} orders={orders}/>
    </>
  )
}

export default Orders;