import React, { Component } from 'react'
import Filters from './Filters.js'

class Medecins extends Component {
  state={
    medecins:[],
    specialites:[],
    classifications:[],
    produits:[],
    commerciaux:[],
    pages:0,
    page:0,
    next:0,
    previous:0,
    length:0,
    other:""
  }
  get_medecins=async(pays="",wilaya="",commune="",medecin="",commercial="",specialite="",classification="",visites="",produit="",mindate="",maxdate="",priority="",shared="",stock="",note="",deal="",page="")=>{
    await fetch(this.props.urls.medecins
      +`?pays=${pays}&wilaya=${wilaya}&commune=${commune}&medecin=${medecin}&commercial=${commercial}&specialite=${specialite}&classification=${classification}&visites=${visites}&produit=${produit}&mindate=${mindate}&maxdate=${maxdate}&priority=${priority}&shared=${shared}&stock=${stock}&note=${note}&deal=${deal}&page=${page}`)
    .then(response=>response.json())
    .then(response=>this.setState({medecins:response.result,  pages:response.pages,
                                    page:page,
                                    next:response.next,
                                    previous:response.previous,
                                    length:response.length,
                                    other:response.other
                                  }))
  }

  get_commerciaux=async(pays="",wilaya="",commune="",commercial="",page="")=>{
    await fetch(this.props.urls.commerciaux)
    .then(response=>response.json())
    .then(response=>this.setState({commerciaux:response}))
  }

  get_specialite=async()=>{
    await fetch(this.props.urls.specialites)
    .then(response=>response.json())
    .then(response=>this.setState({specialites:response}))

    await fetch(this.props.urls.classifications)
    .then(response=>response.json())
    .then(response=>this.setState({classifications:response}))

    await fetch(this.props.urls.produits)
    .then(response=>response.json())
    .then(response=>this.setState({produits:response}))
  }


  componentDidMount(){
    this.props.changeTitle("liste des medecins")
    this.get_medecins()
    this.get_specialite()
    this.get_commerciaux()
  }

  render() {
    return (
      <React.Fragment>
        <Filters
         pays={this.props.pays}
         getMedecins={this.get_medecins}
         medecins={this.state.medecins}
         specialites={this.state.specialites}
         classifications={this.state.classifications}
         commerciaux={this.state.commerciaux}
         produits={this.state.produits}
         pages={this.state.pages}
         page={this.state.page}
         next={this.state.next}
         previous={this.state.previous}
         length={this.state.length}
         other={this.state.other}
         />
      </React.Fragment>
    )
  }
}

export default Medecins
