import React ,{useState} from 'react'
import axios from 'axios'

export default function Comments({rapport}) {
    
    const [rcomment, setComment] = useState("")
    const [rcomments, setComments] = useState(rapport.comments)
    
    const handleKeyPress=(e)=>{
        setComment(e.target.value)
    }

    const send_comment=async()=>{
        axios.get(`rapports/comments/add/${rapport.id}?content=${rcomment}`)
        .then(response=>{
            if (response.status==200)
            {   
                console.log("the response *****",response)
                console.log("the data *****",response.data)
                setComments([...rcomments, response.data])
                setComment("")
                document.getElementById(`comment-${rapport.id}`).value = ''
            }
            else 
                alert("please try again")    
        })
        .catch(error=>{
           console.log(error);
           alert("please try again")  
        })
    }
    return (
        <div>
            {rcomments.map(comment=>(
                <div><b> {comment.user.username}:</b> <small> {comment.comment}</small></div>
              ))}

                <textarea class="form-control mt-1" placeholder="Add a comment here"  onKeyUp={(e)=>{handleKeyPress(e)}} id={`comment-${rapport.id}`}></textarea>
                <div className="text-center">
                    <div className="btn btn-sm btn-success mt-2" onClick={()=>{send_comment()}}>Envoyer</div>
                </div>
        </div>
    )
}
