import React, { Component } from 'react'
import Filters from './Filters.js'


class Rapports extends Component {
  state={
    rapports:[],
    specialites:[],
    classifications:[],
    produits:[],
    pages:0,
    page:0,
    next:0,
    previous:0,
    length:0,
    visites_length:0,
    medecins_length:0,
    commerciaux:[],
    other:''
  }

  format_date=(date)=>{

    var day=(date.getDate()<10) ? '0'+date.getDate() : date.getDate()
    var month=(date.getMonth()+1<10) ? '0'+(date.getMonth()+1) : (date.getMonth()+1)


    return  `${date.getFullYear()}-${month}-${day}`
  }


  get_rapports=async(pays="",wilaya="",commune="",priority="",commercial="",medecin="",page="",min_date=this.format_date(new Date()),max_date="",specialite="",classification="",produit="",note="")=>{
    await fetch(this.props.urls.rapports
      +`?pays=${pays}&wilaya=${wilaya}&commune=${commune}&priority=${priority}&commercial=${commercial}&medecin=${medecin}&page=${page}&mindate=${min_date}&maxdate=${max_date}&specialite=${specialite}&classification=${classification}&produit=${produit}&note=${note}`)
    .then(response=>response.json())
    .then(response=>this.setState({ rapports:response.result,  pages:response.pages,
                                    page:page,
                                    next:response.next,
                                    previous:response.previous,
                                    length:response.length,
                                    visites_length:response.visites,
                                    medecins_length:response.medecins,
                                    other:response.other
                                  }))
  }
  get_specialite=async()=>{
    await fetch(this.props.urls.specialites)
    .then(response=>response.json())
    .then(response=>this.setState({specialites:response}))

    await fetch(this.props.urls.classifications)
    .then(response=>response.json())
    .then(response=>this.setState({classifications:response}))
  }
  get_produits=async()=>{
    await fetch(this.props.urls.produits)
    .then(response=>response.json())
    .then(response=>this.setState({produits:response}))
  }

  get_commerciaux=async(pays="",wilaya="",commune="",commercial="",page="")=>{
    await fetch(this.props.urls.commerciaux)
    .then(response=>response.json())
    .then(response=>this.setState({commerciaux:response}))
  }
  componentDidMount(){
    this.props.changeTitle("liste des rapports")
    this.get_rapports()
    this.get_specialite()
    this.get_produits()
    this.get_commerciaux()
  }
  render() {
    return (
      <React.Fragment>
        <Filters
         pays={this.props.pays}
         getRapports={this.get_rapports}
         rapports={this.state.rapports}
         specialites={this.state.specialites}
         classifications={this.state.classifications}
         produits={this.state.produits}
         pages={this.state.pages}
         page={this.state.page}
         next={this.state.next}
         previous={this.state.previous}
         length={this.state.length}
         visitesLen={this.state.visites_length}
         medecinsLen={this.state.medecins_length}
         commerciaux={this.state.commerciaux}
         other={this.state.other}
         />
      </React.Fragment>
    )
  }
}

export default Rapports
