import React, { useState } from 'react'

export default function Tasks({tasks}) {
    const [_show, set_show] = useState(true)
  return (
    <div>
        <div className="text-dark" onClick={()=>set_show(!_show)}>
            <b>{!_show ?  "afficher" : "cacher"} taches</b>
        </div>
        <div className={!_show && "d-none"}>
            {tasks.map(task=>(
                <div key={task.id} > 
                    <span className={ !task.completed ? "text-dark" : "text-success"}>•</span>   {task.task} <br/>
                </div>
            ))}
        </div>
    </div>
  )
}
