import React, { Component } from 'react'
import List from './List.js'
import Pagination from './Pagination.js'
import DatePicker from "react-datepicker";
import "react-datepicker/dist/react-datepicker.css";

class Filters extends Component {
  state={
    selected_pays:0,
    selected_wilaya:0,
    selected_commune:0,
    selected_priority:0,
    commercial:"",
    medecin:"",
    specialite:"",
    classification:"",
    produit:"",
    min_date:'',
    max_date:'',
    note:''
  }



  get_by_page=(page)=>{
    this.props.getRapports(
      this.state.selected_pays,
      this.state.selected_wilaya,
      this.state.selected_commune,
      this.state.selected_priority,
      this.state.commercial,
      this.state.medecin,
      page,
      this.state.min_date,
      this.state.max_date,
      this.state.specialite,
      this.state.classification,
      this.state.produit,
      this.state.note
    )
  }
  linkforpdf=()=>{
    return `/rapports/PDF/?pays=${this.state.selected_pays}&wilaya=${this.state.selected_wilaya}&commune=${this.state.selected_commune}&priority=${this.state.selected_priority}&commercial=${this.state.commercial}&medecin=${this.state.medecin}&mindate=${this.state.min_date}&maxdate=${this.state.max_date}&specialite=${this.state.specialite}&classification=${this.state.classification}&produit=${this.state.produit}&note=${this.state.note}`
  }

  componentDidMount(){
    setTimeout(function(){
      document.getElementById('select-init').click()
      // document.getElementById('select-init').dispatchEvent(new MouseEvent("click",{bubbles: true, cancellable: true}));
    },2000)
  }

  min_dateChange=date => {
    try{
      var day=(date.getDate()<10) ? '0'+date.getDate() : date.getDate()
      var month=(date.getMonth()+1<10) ? '0'+(date.getMonth()+1) : (date.getMonth()+1)
      this.min_date_picker=date
      this.setState({min_date: `${date.getFullYear()}-${month}-${day}`});
      this.props.getRapports(
        this.state.selected_pays,
        this.state.selected_wilaya,
        this.state.selected_commune,
        this.state.selected_priority,
        this.state.commercial,
        this.state.medecin,
        "",
        `${date.getFullYear()}-${month}-${day}`,
        this.state.max_date,
        this.state.specialite,
        this.state.classification,
        this.state.produit,
        this.state.note
      )
    }catch{
      this.setState({min_date:""});this.min_date_picker="";
      this.props.getRapports(
        this.state.selected_pays,
        this.state.selected_wilaya,
        this.state.selected_commune,
        this.state.selected_priority,
        this.state.commercial,
        this.state.medecin,
        "",
        "",
        this.state.max_date,
        this.state.specialite,
        this.state.classification,
        this.state.produit,
        this.state.note
      )
    }

  };
  max_dateChange=date => {
    try{
      var day=(date.getDate()<10) ? '0'+date.getDate() : date.getDate()
      var month=(date.getMonth()+1<10) ? '0'+(date.getMonth()+1) : (date.getMonth()+1)
      this.max_date_picker=date
      this.setState({max_date: `${date.getFullYear()}-${month}-${day}`});
      this.props.getRapports(
        this.state.selected_pays,
        this.state.selected_wilaya,
        this.state.selected_commune,
        this.state.selected_priority,
        this.state.commercial,
        this.state.medecin,
        "",
        this.state.min_date,
        `${date.getFullYear()}-${month}-${day}`,
        this.state.specialite,
        this.state.classification,
        this.state.produit,
        this.state.note
      )
    }catch{
      this.setState({max_date:""});this.max_date_picker="";
      this.props.getRapports(
        this.state.selected_pays,
        this.state.selected_wilaya,
        this.state.selected_commune,
        this.state.selected_priority,
        this.state.commercial,
        this.state.medecin,
        "",
        this.state.min_date,
        "",
        this.state.specialite,
        this.state.classification,
        this.state.produit,
        this.state.note
      )
    }
  };

  render() {
    return (
      <React.Fragment>
      <div className="py-4 container text-secondary">
        <div className="row">
        <div className="col-md pb-2">
          <b>Country:</b>
          <select className="form-control"
          onChange={(e)=>{this.setState({selected_pays:e.target.value,selected_wilaya:0,selected_commune:0});
          this.props.getRapports(
            e.target.value,
            "",
            "",
            this.state.selected_priority,
            this.state.commercial,
            this.state.medecin,
            "",
            this.state.min_date,
            this.state.max_date,
            this.state.specialite,
            this.state.classification,
            this.state.produit,
            this.state.note
          )}}>
          <option value="0">Tous les pays</option>
          {this.props.pays.map(pys=>(
            <option key={pys.id} value={pys.id} >{pys.nom}</option>
          ))}
          </select>
        </div>
          <div className="col-md pb-2">
            <b>Wilaya:</b>
            <select className="form-control"
            onChange={(e)=>{this.setState({selected_wilaya:e.target.value,selected_commune:0});
            this.props.getRapports(
              "",
              e.target.value,
              "",
              this.state.selected_priority,
              this.state.commercial,
              this.state.medecin,
              "",
              this.state.min_date,
              this.state.max_date,
              this.state.specialite,
              this.state.classification,
              this.state.produit,
              this.state.note
            )}}>
            <option value="0">Toutes les wilayas</option>
            {this.props.pays.map(pys=>{
              if((this.state.selected_pays==0) ||(this.state.selected_pays==pys.id))
              return pys.wilayas_list.map(wilaya=>(
                <option key={wilaya.id} value={wilaya.id}>{wilaya.nom}</option>
              ))
            })}
            </select>
          </div>
          <div className="col-md pb-2">
            <b>Commune:</b>
            <select className="form-control"
            onChange={(e)=>{this.setState({selected_commune:e.target.value});
            this.props.getRapports(
              "",
              "",
              e.target.value,
              this.state.selected_priority,
              this.state.commercial,
              this.state.medecin,
              "",
              this.state.min_date,
              this.state.max_date,
              this.state.specialite,
              this.state.classification,
              this.state.produit,
              this.state.note
            )}}>
            <option value="0">Toutes les communes</option>
            {this.props.pays.map(pys=>{
              if((this.state.selected_pays==0) ||(this.state.selected_pays==pys.id))
              return pys.wilayas_list.map(wilaya=>{
                if((this.state.selected_wilaya==0) ||(this.state.selected_wilaya==wilaya.id))
                return wilaya.communes.map(commune=>(
                  <option key={commune.id} value={commune.id}>{commune.nom}</option>
                ))
              })
            })}
            </select>
          </div>
          <div className="col-md pb-2">
            <b>Priorité:</b>
            <select className="form-control"
             onChange={(e)=>{
               this.setState({selected_priority:e.target.value});
               this.props.getRapports(
                 this.state.selected_pays,
                 this.state.selected_wilaya,
                 this.state.selected_commune,
                 e.target.value,
                 this.state.commercial,
                 this.state.medecin,
                 "",
                 this.state.min_date,
                 this.state.max_date,
                 this.state.specialite,
                 this.state.classification,
                 this.state.produit,
                 this.state.note
               )}}>
              <option value="0">0</option>
              <option value="1">1</option>
              <option value="2">2</option>
              <option value="3">3</option>
              <option value="4">4</option>
              <option value="5">5</option>
            </select>
          </div>
          <div className="col-md pb-2">
              <b>Date min:</b><br/>
              <DatePicker className="form-control"  dateFormat="dd/MM/yyyy" selected={this.min_date_picker ? this.min_date_picker : new Date()} onChange={this.min_dateChange} required/>
          </div>
          <div className="col-md pb-2">
              <b>Date max:</b><br/>
              <DatePicker className="form-control"  dateFormat="dd/MM/yyyy" selected={this.max_date_picker} onChange={this.max_dateChange} required/>
          </div>


        </div>
        <div className="row">

        <div className="col-md pb-2">
          <b>Délégué:</b>
          <select  className="form-control"
          onChange={(e)=>{this.setState({commercial:e.target.value});
          this.props.getRapports(
            this.state.selected_pays,
            this.state.selected_wilaya,
            this.state.selected_commune,
            this.state.selected_priority,
            e.target.value,
            this.state.medecin,
            "",
            this.state.min_date,
            this.state.max_date,
            this.state.specialite,
            this.state.classification,
            this.state.produit,
            this.state.note
          )
          }}>
          <option value=""> Tous</option>
          {this.props.commerciaux.map(commercial=>{
              if ((commercial.country==this.state.selected_pays)||(this.state.selected_pays==0))
              return(
                <option key={commercial.id} value={commercial.username}>{commercial.username}</option>
                )
            })}
          </select>
        </div>

          <div className="col-md pb-2">
            <b>Medecin:</b>
            <input type="text" className="form-control"
            onChange={(e)=>{this.setState({medecin:e.target.value})
            this.props.getRapports(
              this.state.selected_pays,
              this.state.selected_wilaya,
              this.state.selected_commune,
              this.state.selected_priority,
              this.state.commercial,
              e.target.value,
              "",
              this.state.min_date,
              this.state.max_date,
              this.state.specialite,
              this.state.classification,
              this.state.produit,
              this.state.note
            )
          }}/>
          </div>
          <div className="col-md pb-2">
            <b>Specialite:</b>
            <input  id="rapport_spec" type="text" class="d-none"
            onChange={(e)=>{this.setState({specialite:e.target.value})
            this.props.getRapports(
              this.state.selected_pays,
              this.state.selected_wilaya,
              this.state.selected_commune,
              this.state.selected_priority,
              this.state.commercial,
              this.state.medecin,
              "",
              this.state.min_date,
              this.state.max_date,
              e.target.value,
              this.state.classification,
              this.state.produit,
              this.state.note
            );
          }}
            />
            <select className="w-100 specialite multiple" multiple="multiple" data-target={"rapport_spec"}>
            <option value=""> Toutes</option>
            <option value="medicale"> Medicale </option>
            <option value="commerciale"> Commerciale </option>
            {this.props.specialites.map(spec=>(
              <option key={spec.id} value={spec.nom}>{spec.nom}</option>
            ))}
            </select>
          </div>
          <div className="col-md pb-2">
            <b>Classification:</b>
            <input id="rapport_class" type="text" class="d-none"
            onChange={(e)=>{this.setState({classification:e.target.value})
            this.props.getRapports(
              this.state.selected_pays,
              this.state.selected_wilaya,
              this.state.selected_commune,
              this.state.selected_priority,
              this.state.commercial,
              this.state.medecin,
              "",
              this.state.min_date,
              this.state.max_date,
              this.state.specialite,
              e.target.value,
              this.state.produit,
              this.state.note
            )
          }}
            />
            <select className="w-100 specialite multiple" multiple="multiple" data-target={"rapport_class"}>
            <option value=""> Toutes</option>
            {this.props.classifications.map(classification=>(
              <option key={classification.id} value={classification.nom}>{classification.nom}</option>
            ))}
            </select>
          </div>
          <div className="col-md pb-2">
            <b>Produit:</b>
            <select className="form-control"
            onChange={(e)=>{this.setState({produit:e.target.value})
            this.props.getRapports(
              this.state.selected_pays,
              this.state.selected_wilaya,
              this.state.selected_commune,
              this.state.selected_priority,
              this.state.commercial,
              this.state.medecin,
              "",
              this.state.min_date,
              this.state.max_date,
              this.state.specialite,
              this.state.classification,
              e.target.value,
              this.state.note
            )
          }}>
            <option value=""> Tous</option>
            {this.props.produits.map(produit=>{
              if ((produit.pays.includes(parseInt(this.state.selected_pays)))||(this.state.selected_pays==0))
              return(
                <option key={produit.id} value={produit.id}>{produit.nom}</option>
                )
            }
            )}
            </select>
          </div>
          <div className="col-md pb-2">
            <b>Note:</b>
            <select className="form-control"
            onChange={(e)=>{this.setState({note:e.target.value})
            this.props.getRapports(
              this.state.selected_pays,
              this.state.selected_wilaya,
              this.state.selected_commune,
              this.state.selected_priority,
              this.state.commercial,
              this.state.medecin,
              "",
              this.state.min_date,
              this.state.max_date,
              this.state.specialite,
              this.state.classification,
              this.state.produit,
              e.target.value
            )
          }}>
            <option value=""> Tous</option>
            <option value="0"> Non noté</option>
            <option value="1"> 1 </option>
            <option value="2"> 2 </option>
            <option value="3"> 3 </option>
            <option value="4"> 4 </option>
            <option value="5"> 5 </option>

            </select>
          </div>


        </div>
      </div>
      <List
      rapports={this.props.rapports}
      length={this.props.length}
      visitesLen={this.props.visitesLen}
      medecinsLen={this.props.medecinsLen}
      pdflink={this.linkforpdf}
      other={this.props.other}
      />

      <Pagination
        pages={this.props.pages}
        page={this.props.page}
        next={this.props.next}
        previous={this.props.previous}
        getByPage={this.get_by_page}
      />
      </React.Fragment>
    )
  }
}

export default Filters
